  1→/**
  2→ * Orchestrator Acceptance Test Kit
  3→ *
  4→ * Extends the smoke-test-kit with orchestrator-specific helpers.
  5→ * Boots a Brain server + SurrealDB with isolated namespace.
  6→ * Provides helpers for workspace/task/session setup and agent spawning mock.
  7→ */
  8→import { afterAll, beforeAll } from "bun:test";
  9→import { createHash, randomBytes } from "node:crypto";
 10→import { readFileSync } from "node:fs";
 11→import { join } from "node:path";
 12→import { RecordId, Surreal } from "surrealdb";
 13→
 14→// ---------------------------------------------------------------------------
 15→// Types
 16→// ---------------------------------------------------------------------------
 17→
 18→export type OrchestratorTestRuntime = {
 19→  baseUrl: string;
 20→  surreal: Surreal;
 21→  namespace: string;
 22→  database: string;
 23→  port: number;
 24→};
 25→
 26→export type TestUser = {
 27→  headers: Record<string, string>;
 28→};
 29→
 30→export type TestWorkspace = {
 31→  workspaceId: string;
 32→  conversationId: string;
 33→};
 34→
 35→export type TestTask = {
 36→  taskId: string;
 37→  taskRecord: RecordId<"task">;
 38→};
 39→
 40→export type TestProject = {
 41→  projectId: string;
 42→  projectRecord: RecordId<"project">;
 43→};
 44→
 45→export type AssignmentResponse = {
 46→  agentSessionId: string;
 47→  streamId: string;
 48→  streamUrl: string;
 49→};
 50→
 51→export type SessionStatusResponse = {
 52→  agentSessionId: string;
 53→  orchestratorStatus: string;
 54→  worktreeBranch?: string;
 55→  startedAt: string;
 56→  lastEventAt?: string;
 57→};
 58→
 59→export type ReviewResponse = {
 60→  taskTitle: string;
 61→  diff: {
 62→    files: Array<{
 63→      path: string;
 64→      status: "added" | "modified" | "deleted";
 65→      additions: number;
 66→      deletions: number;
 67→    }>;
 68→    rawDiff: string;
 69→    stats: {
 70→      filesChanged: number;
 71→      insertions: number;
 72→      deletions: number;
 73→    };
 74→  };
 75→  session: {
 76→    orchestratorStatus: string;
 77→    worktreeBranch?: string;
 78→    startedAt?: string;
 79→    lastEventAt?: string;
 80→    toolCallCount?: number;
 81→    filesEdited?: number;
 82→  };
 83→};
 84→
 85→export type TestUserWithToken = TestUser & {
 86→  bearerHeaders: Record<string, string>;
 87→  accessToken: string;
 88→};
 89→
 90→// ---------------------------------------------------------------------------
 91→// Infrastructure Setup
 92→// ---------------------------------------------------------------------------
 93→
 94→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 95→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 96→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 97→const portBase = Number(process.env.SMOKE_PORT_BASE ?? "3200");
 98→
 99→export function setupOrchestratorSuite(
100→  suiteName: string,
101→): () => OrchestratorTestRuntime {
102→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
103→  const namespace = `orch_${runId}`;
104→  const suiteSlug = suiteName
105→    .toLowerCase()
106→    .replace(/[^a-z0-9]+/g, "_")
107→    .replace(/^_+|_+$/g, "");
108→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
109→
110→  let runtime: OrchestratorTestRuntime | undefined;
111→  let serverProcess: ReturnType<typeof Bun.spawn> | undefined;
112→  let setupSucceeded = false;
113→
114→  beforeAll(async () => {
115→    const port = portBase + Math.floor(Math.random() * 20000);
116→    const baseUrl = `http://127.0.0.1:${port}`;
117→
118→    const surreal = new Surreal();
119→    await withTimeout(
120→      () => surreal.connect(surrealUrl),
121→      10_000,
122→      "connect to SurrealDB",
123→    );
124→    await withTimeout(
125→      () =>
126→        surreal.signin({
127→          username: surrealUsername,
128→          password: surrealPassword,
129→        }),
130→      10_000,
131→      "authenticate with SurrealDB",
132→    );
133→
134→    await withTimeout(
135→      () => surreal.query(`DEFINE NAMESPACE ${namespace};`),
136→      10_000,
137→      "define test namespace",
138→    );
139→    await withTimeout(
140→      () => surreal.use({ namespace }),
141→      10_000,
142→      "switch to test namespace",
143→    );
144→    await withTimeout(
145→      () => surreal.query(`DEFINE DATABASE ${database};`),
146→      10_000,
147→      "define test database",
148→    );
149→    await withTimeout(
150→      () => surreal.use({ namespace, database }),
151→      10_000,
152→      "switch to test namespace/database",
153→    );
154→
155→    const schemaSql = readFileSync(
156→      join(process.cwd(), "schema", "surreal-schema.surql"),
157→      "utf8",
158→    );
159→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
160→
161→    serverProcess = Bun.spawn(["bun", "run", "app/server.ts"], {
162→      cwd: process.cwd(),
163→      env: {
164→        ...process.env,
165→        PORT: String(port),
166→        SURREAL_NAMESPACE: namespace,
167→        SURREAL_DATABASE: database,
168→        BETTER_AUTH_URL: baseUrl,
169→        BETTER_AUTH_SECRET:
170→          process.env.BETTER_AUTH_SECRET ??
171→          "smoke-test-secret-at-least-32-chars-long",
172→        GITHUB_CLIENT_ID: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
173→        GITHUB_CLIENT_SECRET:
174→          process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
175→        // Orchestrator-specific: disable real agent spawning in tests
176→        ORCHESTRATOR_MOCK_AGENT: "true",
177→      },
178→      stdout: "pipe",
179→      stderr: "inherit",
180→    });
181→
182→    await waitForHealth(baseUrl, serverProcess, 15_000);
183→    runtime = { baseUrl, surreal, namespace, database, port };
184→    setupSucceeded = true;
185→  }, 60_000);
186→
187→  afterAll(async () => {
188→    if (serverProcess) {
189→      serverProcess.kill();
190→      await serverProcess.exited;
191→    }
192→
193→    if (!runtime) return;
194→
195→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
196→      try {
197→        await withTimeout(
198→          () => runtime!.surreal.query(`REMOVE DATABASE ${database};`),
199→          10_000,
200→          "remove test database",
201→        );
202→      } catch {
203→        // Best effort cleanup.
204→      }
205→
206→      try {
207→        await withTimeout(
208→          () => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`),
209→          10_000,
210→          "remove test namespace",
211→        );
212→      } catch {
213→        // Best effort cleanup.
214→      }
215→    }
216→
217→    await withTimeout(
218→      () => runtime!.surreal.close(),
219→      2_000,
220→      "close SurrealDB",
221→    ).catch(() => undefined);
222→  }, 20_000);
223→
224→  return () => {
225→    if (!runtime) {
226→      throw new Error(
227→        "Orchestrator runtime requested before suite setup completed",
228→      );
229→    }
230→    return runtime;
231→  };
232→}
233→
234→// ---------------------------------------------------------------------------
235→// Domain Helpers -- Business Language Layer
236→// ---------------------------------------------------------------------------
237→
238→/**
239→ * Creates an authenticated test user and returns auth headers.
240→ */
241→export async function createTestUser(
242→  baseUrl: string,
243→  suffix: string,
244→): Promise<TestUser> {
245→  const email = `orch-${Date.now()}-${suffix}@test.local`;
246→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
247→    method: "POST",
248→    headers: { "Content-Type": "application/json" },
249→    body: JSON.stringify({
250→      name: "Test User",
251→      email,
252→      password: "test-password-123",
253→    }),
254→    redirect: "manual",
255→  });
256→
257→  if (!response.ok) {
258→    const body = await response.text();
259→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
260→  }
261→
262→  const setCookie = response.headers.getSetCookie();
263→  if (!setCookie || setCookie.length === 0) {
264→    throw new Error("Sign-up did not return session cookies");
265→  }
266→
267→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
268→  return { headers: { Cookie: cookieHeader } };
269→}
270→
271→/**
272→ * Creates a workspace for testing.
273→ */
274→export async function createTestWorkspace(
275→  baseUrl: string,
276→  user: TestUser,
277→  name?: string,
278→  options?: { repoPath?: string | false },
279→): Promise<TestWorkspace> {
280→  // Default to process.cwd() (a valid git repo) unless explicitly disabled
281→  const repoPath = options?.repoPath === false
282→    ? undefined
283→    : (options?.repoPath ?? process.cwd());
284→
285→  const workspace = await fetchJson<TestWorkspace>(
286→    `${baseUrl}/api/workspaces`,
287→    {
288→      method: "POST",
289→      headers: { "Content-Type": "application/json", ...user.headers },
290→      body: JSON.stringify({
291→        name: name ?? `Orchestrator Test ${Date.now()}`,
292→        ...(repoPath ? { repoPath } : {}),
293→      }),
294→    },
295→  );
296→  return workspace;
297→}
298→
299→/**
300→ * Creates a task in assignable status via direct DB insertion.
301→ * Uses SurrealDB directly because task creation normally goes through
302→ * the extraction pipeline or PM agent, but acceptance tests need
303→ * tasks in specific states as preconditions.
304→ */
305→export async function createReadyTask(
306→  surreal: Surreal,
307→  workspaceId: string,
308→  options: {
309→    title: string;
310→    description?: string;
311→    status?: string;
312→    projectId?: string;
313→  },
314→): Promise<TestTask> {
315→  const taskId = `test-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
316→  const taskRecord = new RecordId("task", taskId);
317→  const workspaceRecord = new RecordId("workspace", workspaceId);
318→
319→  const content: Record<string, unknown> = {
320→    title: options.title,
321→    description: options.description ?? "Test task for orchestrator acceptance tests",
322→    status: options.status ?? "ready",
323→    created_at: new Date(),
324→    updated_at: new Date(),
325→    workspace: workspaceRecord,
326→  };
327→
328→  if (options.projectId) {
329→    const projectRecord = new RecordId("project", options.projectId);
330→    await surreal.query(
331→      `CREATE $task CONTENT $content;
332→       RELATE $task->belongs_to->$project SET added_at = time::now();`,
333→      { task: taskRecord, content: { ...content }, project: projectRecord },
334→    );
335→  } else {
336→    await surreal.query(`CREATE $task CONTENT $content;`, {
337→      task: taskRecord,
338→      content,
339→    });
340→  }
341→
342→  return { taskId, taskRecord };
343→}
344→
345→/**
346→ * Creates a project for grouping tasks.
347→ */
348→export async function createTestProject(
349→  surreal: Surreal,
350→  workspaceId: string,
