513→
514→/**
515→ * Queries agent session records for a task.
516→ */
517→export async function getAgentSessionsForTask(
518→  surreal: Surreal,
519→  taskId: string,
520→): Promise<
521→  Array<{
522→    id: RecordId;
523→    orchestrator_status: string;
524→    agent: string;
525→  }>
526→> {
527→  const taskRecord = new RecordId("task", taskId);
528→  const rows = (await surreal.query(
529→    `SELECT id, orchestrator_status, agent FROM agent_session WHERE task_id = $task;`,
530→    { task: taskRecord },
531→  )) as Array<
532→    Array<{ id: RecordId; orchestrator_status: string; agent: string }>
533→  >;
