536→
537→/**
538→ * Transitions an agent session to a given status via direct DB update.
539→ * Used in tests to simulate agent lifecycle without a real agent process.
540→ */
541→export async function simulateSessionStatus(
542→  surreal: Surreal,
543→  sessionId: string,
544→  status: string,
545→): Promise<void> {
546→  const sessionRecord = new RecordId("agent_session", sessionId);
547→  await surreal.update(sessionRecord).merge({
548→    orchestrator_status: status,
549→  });
