  1→import { afterAll, beforeAll, describe, expect, it } from "bun:test";
  2→import { randomUUID } from "node:crypto";
  3→import { readFileSync } from "node:fs";
  4→import { join } from "node:path";
  5→import { RecordId, Surreal } from "surrealdb";
  6→
  7→/**
  8→ * US-UI-005: Dual-Label Audit Trail Query
  9→ *
 10→ * Validates the audit trail queries that return dual-label attribution:
 11→ * - Agent actions show actor identity + accountable human via managed_by chain
 12→ * - Human actions show self as both actor and accountable
 13→ * - Mixed human/agent attribution handled in query results
 14→ * - "Agent suggestions that became tasks" query works with identity references
 15→ * - No unattributed entities in workspace after migration
 16→ */
 17→
 18→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 19→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 20→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 21→
 22→let surreal: Surreal;
 23→let namespace: string;
 24→let database: string;
 25→let workspaceRecord: RecordId<"workspace", string>;
 26→let humanIdentity: RecordId<"identity", string>;
 27→let agentIdentity: RecordId<"identity", string>;
 28→let agentRecord: RecordId<"agent", string>;
 29→
 30→beforeAll(async () => {
 31→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 32→  namespace = `smoke_audit_trail_${runId}`;
 33→  database = `audit_${Math.floor(Math.random() * 100000)}`;
 34→
 35→  surreal = new Surreal();
 36→  await surreal.connect(surrealUrl);
 37→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 38→  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
 39→  await surreal.use({ namespace });
 40→  await surreal.query(`DEFINE DATABASE ${database};`);
 41→  await surreal.use({ namespace, database });
 42→
 43→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 44→  await surreal.query(schemaSql);
 45→
 46→  const now = new Date();
 47→
 48→  workspaceRecord = new RecordId("workspace", randomUUID());
 49→  await surreal.create(workspaceRecord).content({
 50→    name: "Audit Trail Test",
 51→    status: "active",
 52→    onboarding_complete: true,
 53→    onboarding_turn_count: 0,
 54→    onboarding_summary_pending: false,
 55→    onboarding_started_at: now,
 56→    created_at: now,
 57→  });
 58→
 59→  // Human identity
 60→  humanIdentity = new RecordId("identity", randomUUID());
 61→  await surreal.query("CREATE $record CONTENT $content;", {
 62→    record: humanIdentity,
 63→    content: {
 64→      name: "Marcus Oliveira",
 65→      type: "human",
 66→      role: "owner",
 67→      workspace: workspaceRecord,
 68→      created_at: now,
 69→    },
 70→  });
 71→
 72→  // Agent spoke with managed_by
 73→  agentRecord = new RecordId("agent", randomUUID());
 74→  await surreal.query("CREATE $record CONTENT $content;", {
 75→    record: agentRecord,
 76→    content: {
 77→      agent_type: "management",
 78→      model: "claude-sonnet-4-20250514",
 79→      managed_by: humanIdentity,
 80→      created_at: now,
 81→    },
 82→  });
 83→
 84→  // Agent identity
 85→  agentIdentity = new RecordId("identity", randomUUID());
 86→  await surreal.query("CREATE $record CONTENT $content;", {
 87→    record: agentIdentity,
 88→    content: {
 89→      name: "PM Agent",
 90→      type: "agent",
 91→      role: "management",
 92→      workspace: workspaceRecord,
 93→      created_at: now,
 94→    },
 95→  });
 96→
 97→  // Spoke edge: agent identity -> agent
 98→  await surreal.query(
 99→    "RELATE $identity->identity_agent->$agent SET added_at = $now;",
100→    { identity: agentIdentity, agent: agentRecord, now },
101→  );
102→}, 60_000);
103→
104→afterAll(async () => {
105→  if (!surreal) return;
106→  try {
107→    await surreal.query(`REMOVE DATABASE ${database};`);
108→    await surreal.query(`REMOVE NAMESPACE ${namespace};`);
109→  } catch {}
110→  await surreal.close().catch(() => {});
111→}, 10_000);
