141→    expect(actorRows[0].actor_name).toBe("PM Agent");
142→    expect(actorRows[0].actor_type).toBe("agent");
143→
144→    // Step 2: traverse managed_by chain from agent identity
145→    const [managedByRows] = await surreal.query<
146→      [Array<{ managed_by_name: string; managed_by_type: string }>]
147→    >(
148→      `SELECT ->identity_agent->agent.managed_by.name AS managed_by_name, ->identity_agent->agent.managed_by.type AS managed_by_type FROM $identity;`,
149→      { identity: actorRows[0].owner_id },
150→    );
