  8→/**
  9→ * US-UI-03-01: Role-based authority with per-identity overrides
 10→ *
 11→ * Resolution order: per-identity override -> role default -> agent_type default -> blocked
 12→ * Human identities bypass authority checks entirely.
 13→ * Per-identity authorized_to override takes precedence over role-based authority_scope.
 14→ */
 15→
 16→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 17→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 18→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 19→
 20→let surreal: Surreal;
 21→let namespace: string;
 22→let database: string;
 23→let workspaceRecord: RecordId<"workspace", string>;
 24→
 25→beforeAll(async () => {
 26→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 27→  namespace = `smoke_authority_${runId}`;
 28→  database = `authority_${Math.floor(Math.random() * 100000)}`;
 29→
 30→  surreal = new Surreal();
 31→  await surreal.connect(surrealUrl);
 32→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 33→  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
 34→  await surreal.use({ namespace });
 35→  await surreal.query(`DEFINE DATABASE ${database};`);
 36→  await surreal.use({ namespace, database });
 37→
 38→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 39→  await surreal.query(schemaSql);
 40→
 41→  const now = new Date();
 42→  workspaceRecord = new RecordId("workspace", randomUUID());
 43→  await surreal.create(workspaceRecord).content({
 44→    name: "Authority Test Workspace",
 45→    status: "active",
 46→    onboarding_complete: true,
 47→    onboarding_turn_count: 0,
 48→    onboarding_summary_pending: false,
 49→    onboarding_started_at: now,
 50→    created_at: now,
 51→  });
 52→}, 60_000);
 53→
 54→afterAll(async () => {
 55→  if (!surreal) return;
 56→  try {
 57→    await surreal.query(`REMOVE DATABASE ${database};`);
 58→    await surreal.query(`REMOVE NAMESPACE ${namespace};`);
 59→  } catch {}
 60→  await surreal.close().catch(() => {});
 61→}, 10_000);
