 55→    onboarding_turn_count: 0,
 56→    onboarding_summary_pending: false,
 57→    onboarding_started_at: now,
 58→    created_at: now,
 59→  });
 60→
 61→  // Create person (existing spoke target)
 62→  personRecord = new RecordId("person", randomUUID());
 63→  await surreal.query("CREATE $record CONTENT $content;", {
 64→    record: personRecord,
 65→    content: {
 66→      name: "Marcus Oliveira",
